#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);

  // Use sqlgen::write to insert records
  conn_result.and_then([&records](const auto& conn) {
    return sqlgen::write(conn, records);
  }).value(); // Assuming success for simplicity
}

void modify_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id,
                               const std::string& col_name,
                               const std::string& new_value) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);

  // Build the update query using sqlgen's fluent interface
  auto update_query = sqlgen::update(table_name)
    .set(col_name, new_value)
    .where("id"_c == record_id);

  // Execute the update
  conn_result.and_then([&update_query](const auto& conn) {
    return update_query(conn);
  }).value(); // Assuming success for simplicity
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);

  // Use sqlgen::delete_from with where condition to delete the record
  auto delete_query = sqlgen::delete_from(table_name)
    .where("id"_c == record_id);

  // Execute the delete
  conn_result.and_then([&delete_query](const auto& conn) {
    return delete_query(conn);
  }).value(); // Assuming success for simplicity
}
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect(db_path)` to establish connection to the EAS database.

2. **Record Insertion**: Uses `sqlgen::write()` function which handles:
   - Creating the table if it doesn't exist
   - Starting the write transaction
   - Inserting all records
   - Committing the transaction

3. **Record Modification**: Uses `sqlgen::update()` with fluent interface:
   - `set()` to specify which column to update
   - `where()` with `"id"_c == record_id` to target the specific record
   - The `"id"_c` literal creates a column reference using the string literal operator

4. **Record Deletion**: Uses `sqlgen::delete_from()` with:
   - `where()` condition to identify the record by primary key ID
   - The same `"id"_c` literal pattern for column reference

5. **Error Handling**: Uses `.value()` to extract the result, assuming successful execution for simplicity. In production code, proper error handling would be needed.

The implementation follows sqlgen's fluent API design pattern and leverages the library's type-safe query building capabilities as shown in the reference materials.

