 * This function demonstrates how to use upsert (insert or replace) statements in sqlgen write API.
 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  // 1. Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false; // Connection failed
  }

  // 2. Use sqlgen::write() with or_replace=true to perform upsert
  auto write_result = sqlgen::write(conn_result.value(), items, true);
  if (!write_result) {
    return false; // Write operation failed
  }

  // 3. Read back the items using sqlgen::read API
  auto read_result = sqlgen::read<std::vector<Inventory>>(conn_result.value());
  if (!read_result) {
    return false; // Read operation failed
  }

  // 4. Compare results to verify upsert behavior
  // Verify the number of items matches
  if (read_result.value().size() != items.size()) {
    return false;
  }

  // Verify each item's primary key exists in the original data
  std::set<int> original_ids;
  for (const auto& item : items) {
    original_ids.insert(item.item_id);
  }

  for (const auto& read_item : read_result.value()) {
    if (original_ids.find(read_item.item_id) == original_ids.end()) {
      return false; // Found unexpected item ID
    }
  }

  return true; // All checks passed
}

