  using namespace sqlgen;
  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<UserProfile>(conn);
  create_table<UserProfile>(conn);
  insert(conn, std::vector<UserProfile>{{1, "  Alice  ", " alice@example.com  "},
                                        {2, "Bob", "bob@example.com"}});
  auto rows = trim_and_length_validation();
  ASSERT_EQ(rows.size(), 2);
}

